let AboutComponent = () => {

    return (
        <div>
        <h2>Crue Universidades Españolas y el Consejo Superior de Investigaciones Científicas han alcanzado acuerdos transformativos de sus licencias de suscripción con las editoriales Elsevier, Wiley, Springer Nature y American Chemical Society con el objetivo de avanzar en una socialización del conocimiento mediante un creciente acceso libre al mismo.
        </h2>
        <p> Gracias a estas negociaciones, los investigadores e investigadoras de ambas instituciones podrán seguir accediendo a la lectura y descarga de los artículos científicos de las revistas suscritas y publicar más artículos en abierto, sin costes adicionales. Estos acuerdos permitirán que más investigaciones españolas sean leídas, citadas y desarrolladas.
        </p>
        
        </div>
    )
}

  


export default AboutComponent;
